import React, { FC, useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const [messages, setMessages] = useState<Message[]>([
        { role: 'assistant', content: "Bonjour ! Je suis l'assistant IA de KBB App. Je peux vous aider à analyser vos dossiers, résumer vos tâches ou répondre à vos questions sur vos clients. Comment puis-je vous aider aujourd'hui ?" }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const userMessage = input.trim();
        setInput('');
        setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
        setIsLoading(true);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Build Context String
            const context = `
                Tu es l'assistant intelligent du cabinet d'avocats KBB. 
                Voici l'état actuel des données du cabinet :
                - Clients (${clients.length}) : ${clients.map(c => c.name).join(', ')}
                - Dossiers (${cases.length}) : ${cases.map(c => `${c.name} (Client: ${c.client}, Statut: ${c.status})`).join(' | ')}
                - Tâches : ${tasks.map(t => `${t.name} pour ${t.lawyer}, échéance ${t.dueDate}, statut ${t.status}`).join(' | ')}
                - Factures : ${invoices.length} factures enregistrées.

                Réponds de manière professionnelle, concise et en français. 
                Aide l'utilisateur à naviguer dans ces données ou réponds à des questions juridiques générales.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    { role: 'user', parts: [{ text: context }] },
                    ...messages.map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: userMessage }] }
                ],
                config: {
                    temperature: 0.7,
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse }]);
        } catch (error) {
            console.error("AI Error:", error);
            setMessages(prev => [...prev, { role: 'assistant', content: "Une erreur est survenue lors de la communication avec l'IA. Veuillez vérifier votre connexion ou réessayer plus tard." }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex flex-col h-full max-h-screen">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-3xl font-bold text-gray-800 flex items-center">
                    <span className="bg-indigo-600 text-white p-2 rounded-lg mr-3">
                        <AIIcon />
                    </span>
                    Assistant IA KBB
                </h1>
                <div className="text-sm text-gray-500 bg-white px-3 py-1 rounded-full shadow-sm border">
                    Propulsé par Gemini 3 Flash
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-xl flex-1 flex flex-col overflow-hidden border border-gray-100">
                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50">
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`flex max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`flex-shrink-0 h-10 w-10 rounded-xl flex items-center justify-center font-bold shadow-sm ${
                                    msg.role === 'user' ? 'bg-indigo-600 text-white ml-3' : 'bg-white text-indigo-600 mr-3 border'
                                }`}>
                                    {msg.role === 'user' ? 'U' : 'IA'}
                                </div>
                                <div className={`px-5 py-3 rounded-2xl shadow-sm border ${
                                    msg.role === 'user' 
                                    ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                                    : 'bg-white text-gray-800 border-gray-100 rounded-tl-none'
                                }`}>
                                    <p className="text-sm whitespace-pre-wrap leading-relaxed">{msg.content}</p>
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className="flex items-center space-x-2 bg-white px-4 py-2 rounded-full border border-gray-100 shadow-sm">
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                                <span className="text-xs text-gray-400 ml-2">L'IA réfléchit...</span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className="p-4 bg-white border-t border-gray-100">
                    <form onSubmit={handleSend} className="relative max-w-4xl mx-auto flex items-center space-x-3">
                        <input
                            type="text"
                            placeholder="Posez une question sur vos dossiers ou demandez un conseil juridique..."
                            className="flex-1 p-4 pr-14 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all bg-gray-50 hover:bg-white"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-6 bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 transition duration-300 shadow-md disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                            </svg>
                        </button>
                    </form>
                    <p className="text-center text-[10px] text-gray-400 mt-2">
                        L'IA peut faire des erreurs. Vérifiez les informations importantes.
                    </p>
                </div>
            </div>
        </div>
    );
};

export default AIAssistantPage;

import React, { useState } from 'react';
import { usePersistentState } from './hooks/usePersistentState';
import { initialClients, initialCases, initialEvents, initialTasks, initialInvoices, initialAvocats } from './data/mockData';

import Sidebar from './components/Sidebar';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import ClientsPage from './pages/ClientsPage';
import CasesPage from './pages/CasesPage';
import EventsPage from './pages/EventsPage';
import AgendaPage from './pages/AgendaPage';
import ChatPage from './pages/ChatPage';
import BillingPage from './pages/BillingPage';
import AvocatsPage from './pages/AvocatsPage';
import GestionPage from './pages/GestionPage';
import AllInterfacesPage from './pages/AllInterfacesPage';
import AIAssistantPage from './pages/AIAssistantPage';
import { Client, Case, Event, Task, Invoice, Avocat } from './types';

declare const jspdf: any;

function App() {
    const [isAuthenticated, setIsAuthenticated] = usePersistentState('kbb_auth', false);
    const [currentPage, setCurrentPage] = useState('Dashboard');
    const [clients, setClients] = usePersistentState<Client[]>('kbb_clients', initialClients);
    const [cases, setCases] = usePersistentState<Case[]>('kbb_cases', initialCases);
    const [events, setEvents] = usePersistentState<Event[]>('kbb_events', initialEvents);
    const [tasks, setTasks] = usePersistentState<Task[]>('kbb_tasks', initialTasks);
    const [invoices, setInvoices] = usePersistentState<Invoice[]>('kbb_invoices', initialInvoices);
    const [avocats, setAvocats] = usePersistentState<Avocat[]>('kbb_avocats', initialAvocats);

    const lawyerNames = avocats.map((a) => a.fullName);

    const handleLoginSuccess = () => {
        setIsAuthenticated(true);
    };

    const handleLogout = () => {
        setIsAuthenticated(false);
        setCurrentPage('Dashboard');
    };

    // --- PDF Export Logic ---
    const handleExportPDF = (title: string, headers: string[], data: any[][]) => {
        const { jsPDF } = jspdf;
        const doc = new jsPDF();

        doc.setFontSize(18);
        doc.text(`${title} - KBB App`, 14, 22);
        doc.setFontSize(11);
        doc.setTextColor(100);
        doc.text(`Généré le: ${new Date().toLocaleDateString('fr-FR')}`, 14, 30);

        (doc as any).autoTable({
            head: [headers],
            body: data,
            startY: 35,
            theme: 'striped',
            headStyles: { fillColor: [21, 68, 124] },
        });

        const safeTitle = title.toLowerCase().replace(/\s+/g, '-');
        doc.save(`liste-${safeTitle}-kbb-app.pdf`);
    };

    const handleExportClients = () => {
        const headers = ["Nom du Client", "Contact Principal", "Dossiers Actifs"];
        const data = clients.map((c) => [c.name, c.contact, c.cases]);
        handleExportPDF("Clients", headers, data);
    };

    const handleExportCases = () => {
        const headers = ["Référence", "Nom du Dossier", "Client", "Statut"];
        const data = cases.map((c) => [c.id, c.name, c.client, c.status]);
        handleExportPDF("Dossiers", headers, data);
    };

    // --- Data Handlers ---
    const handleAddClient = (newClient: Omit<Client, 'id'>) => {
        setClients(prev => [...prev, { ...newClient, id: (prev.length > 0 ? Math.max(...prev.map(c => c.id)) : 0) + 1 }]);
    };
    const handleAddCase = (newCase: Case) => setCases(prev => [...prev, newCase]);
    const handleAddEvent = (newEvent: Event) => setEvents(prev => [...prev, newEvent]);
    const handleAddTask = (newTask: Omit<Task, 'id'>) => {
        setTasks(prev => [...prev, { ...newTask, id: (prev.length > 0 ? Math.max(...prev.map(t => t.id)) : 0) + 1 }]);
    };
    const handleAddInvoice = (newInvoice: Invoice) => setInvoices(prev => [...prev, newInvoice]);
    const handleAddAvocat = (newAvocat: Avocat) => setAvocats(prev => [...prev, newAvocat]);

    const handleDeleteClient = (id: number) => setClients(clients.filter(c => c.id !== id));
    const handleDeleteCase = (id: string) => setCases(cases.filter(c => c.id !== id));
    const handleDeleteAvocat = (id: string) => setAvocats(avocats.filter(a => a.id !== id));
    const handleDeleteEvent = (id: string) => setEvents(events.filter(e => e.id !== id));
    const handleDeleteTask = (id: number) => setTasks(tasks.filter(t => t.id !== id));
    const handleDeleteInvoice = (id: string) => setInvoices(invoices.filter(i => i.id !== id));

    const renderPage = () => {
        const pageProps = {
            clients, cases, events, tasks, invoices, avocats, lawyerNames,
            onAddClient: handleAddClient, onAddCase: handleAddCase, onAddEvent: handleAddEvent,
            onAddTask: handleAddTask, onAddInvoice: handleAddInvoice, onAddAvocat: handleAddAvocat,
            onDeleteClient: handleDeleteClient, onDeleteCase: handleDeleteCase, onDeleteAvocat: handleDeleteAvocat,
            onDeleteEvent: handleDeleteEvent, onDeleteTask: handleDeleteTask, onDeleteInvoice: handleDeleteInvoice,
            onExportClients: handleExportClients, onExportCases: handleExportCases,
        };

        switch (currentPage) {
            case 'Dashboard': return <DashboardPage clients={clients} cases={cases} events={events} />;
            case 'AIAssistant': return <AIAssistantPage clients={clients} cases={cases} tasks={tasks} invoices={invoices} />;
            case 'Clients': return <ClientsPage clients={clients} onAddClient={handleAddClient} onExport={handleExportClients} />;
            case 'Dossiers': return <CasesPage cases={cases} clients={clients} onAddCase={handleAddCase} onExport={handleExportCases} />;
            case 'Evenements': return <EventsPage events={events} onAddEvent={handleAddEvent} />;
            case 'Agenda': return <AgendaPage tasks={tasks} cases={cases} lawyers={lawyerNames} onAddTask={handleAddTask} />;
            case 'Chat': return <ChatPage />;
            case 'Facturation': return <BillingPage invoices={invoices} cases={cases} onAddInvoice={handleAddInvoice} />;
            case 'Avocats': return <AvocatsPage avocats={avocats} onAddAvocat={handleAddAvocat} />;
            case 'Gestion': return <GestionPage {...pageProps} />;
            case 'All': return <AllInterfacesPage {...pageProps} />;
            default: return <DashboardPage clients={clients} cases={cases} events={events} />;
        }
    };

    if (!isAuthenticated) {
        return <LoginPage onLoginSuccess={handleLoginSuccess} />;
    }

    return (
        <div className="flex h-screen bg-gray-100 font-sans">
            <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} onLogout={handleLogout} />
            <main className="flex-1 overflow-x-hidden overflow-y-auto p-8 custom-scrollbar">
                {renderPage()}
            </main>
        </div>
    );
}

export default App;

// Import React to resolve namespace errors for React.Dispatch and React.SetStateAction types
import React, { useState, useEffect } from 'react';

export const usePersistentState = <T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] => {
    const [state, setState] = useState<T>(() => {
        try {
            const storedValue = window.localStorage.getItem(key);
            return storedValue ? JSON.parse(storedValue) : initialValue;
        } catch (error) {
            console.error("Error reading from localStorage", error);
            return initialValue;
        }
    });

    useEffect(() => {
        try {
            window.localStorage.setItem(key, JSON.stringify(state));
        } catch (error) {
            console.error("Error writing to localStorage", error);
        }
    }, [key, state]);

    return [state, setState];
};

