import React, { FC, useState } from 'react';
import { Task, Case } from '../../types';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Omit<Task, 'id'>) => void;
  cases: Case[];
  lawyers: string[];
}

const TaskModal: FC<TaskModalProps> = ({ isOpen, onClose, onSave, cases, lawyers }) => {
    const today = new Date().toISOString().split('T')[0];
    const initialFormState = {
        name: '',
        caseId: '',
        lawyer: lawyers[0] || '',
        dueDate: today,
        status: 'Non effectué' as Task['status'],
        notes: '',
    };
    const [formData, setFormData] = useState(initialFormState);

    if (!isOpen) return null;

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.caseId) {
            alert("Veuillez sélectionner un dossier.");
            return;
        }
        onSave({
            ...formData,
            status: formData.status as Task['status'],
        });
        setFormData(initialFormState);
        onClose();
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center">
            <div className="bg-white rounded-lg shadow-2xl p-8 max-w-lg w-full">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-gray-800">Créer une nouvelle tâche</h2>
                    <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                </div>
                <form onSubmit={handleSubmit}>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Nom de la Tâche <span className="text-red-500">*</span></label>
                            <input type="text" name="name" value={formData.name} onChange={handleChange} className="w-full p-2 border border-gray-300 rounded-md shadow-sm" required />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Dossier Associé <span className="text-red-500">*</span></label>
                            <select name="caseId" value={formData.caseId} onChange={handleChange} className="w-full p-2 border border-gray-300 rounded-md shadow-sm" required>
                                <option value="" disabled>-- Sélectionner un dossier --</option>
                                {cases.map(c => <option key={c.id} value={c.id}>{c.name} ({c.client})</option>)}
                            </select>
                        </div>
                         <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Avocat Associé</label>
                            <select name="lawyer" value={formData.lawyer} onChange={handleChange} className="w-full p-2 border border-gray-300 rounded-md shadow-sm">
                                {lawyers.map(l => <option key={l} value={l}>{l}</option>)}
                            </select>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Échéance</label>
                                <input type="date" name="dueDate" value={formData.dueDate} onChange={handleChange} className="w-full p-2 border border-gray-300 rounded-md shadow-sm" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Statut</label>
                                <select name="status" value={formData.status} onChange={handleChange} className="w-full p-2 border border-gray-300 rounded-md shadow-sm">
                                    <option>Non effectué</option>
                                    <option>Effectué à moitié</option>
                                    <option>Effectué</option>
                                </select>
                            </div>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Notes / Détails supplémentaires</label>
                            <textarea name="notes" value={formData.notes} onChange={handleChange} rows={3} className="w-full p-2 border border-gray-300 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500" placeholder="Ajoutez des détails sur la tâche..."></textarea>
                        </div>
                    </div>
                    <div className="mt-8 flex justify-end space-x-4">
                        <button type="button" onClick={onClose} className="bg-gray-200 text-gray-800 font-bold py-2 px-6 rounded-lg hover:bg-gray-300 transition duration-300">Annuler</button>
                        <button type="submit" className="bg-indigo-600 text-white font-bold py-2 px-6 rounded-lg hover:bg-indigo-700 transition duration-300 shadow-sm">Enregistrer</button>
                    </div>
                </form>
            </div>
        </div>
    );
};

