        switch (status) {
            case 'Effectué': return 'bg-green-100 text-green-800';
            case 'Non effectué': return 'bg-red-100 text-red-800';
            case 'Effectué à moitié': return 'bg-yellow-100 text-yellow-800';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    return (
        <>
            <PageContainer 
                title="Agenda" 
                buttonLabel="Ajouter une Tâche" 
                onButtonClick={() => setIsModalOpen(true)}
            >
                <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 space-y-4 md:space-y-0">
                    <div className="flex items-center space-x-2 bg-gray-50 p-1 rounded-xl border border-gray-200 w-fit">
                        <button 
                            onClick={() => setShowOnlyOverdue(false)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${!showOnlyOverdue ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                        >
                            Toutes les tâches ({tasks.length})
                        </button>
                        <button 
                            onClick={() => setShowOnlyOverdue(true)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all flex items-center ${showOnlyOverdue ? 'bg-red-50 shadow-sm text-red-600 border border-red-100' : 'text-gray-500 hover:text-gray-700'}`}
                        >
                            Retards ({tasks.filter(t => isOverdue(t)).length})
                            {tasks.filter(t => isOverdue(t)).length > 0 && (
                                <span className="ml-2 flex h-2 w-2 rounded-full bg-red-500 animate-pulse"></span>
                            )}
                        </button>
                    </div>
                    <div className="text-sm text-gray-500 italic">
                        Date d'aujourd'hui : <span className="font-semibold text-gray-700">{new Date().toLocaleDateString('fr-FR')}</span>
                    </div>
                </div>

                <div className="overflow-x-auto rounded-xl border border-gray-100 shadow-sm">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b border-gray-200">
                            <tr className="text-xs text-gray-500 uppercase tracking-wider">
                                <th className="p-4 font-bold">Tâche</th>
                                <th className="p-4 font-bold">Dossier</th>
                                <th className="p-4 font-bold">Échéance</th>
                                <th className="p-4 font-bold">Responsable</th>
                                <th className="p-4 font-bold">Statut</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {filteredTasks.length > 0 ? (
                                filteredTasks.map(task => {
                                    const relatedCase = cases.find(c => c.id === task.caseId);
                                    const late = isOverdue(task);
                                    return (
                                        <tr key={task.id} className={`transition-colors ${late ? 'bg-red-50/50 hover:bg-red-50' : 'hover:bg-gray-50'}`}>
                                            <td className="p-4">
                                                <div className="flex flex-col">
                                                    <span className="font-semibold text-gray-800 flex items-center">
                                                        {task.name}
                                                        {late && (
                                                            <span className="ml-2 px-1.5 py-0.5 bg-red-600 text-[10px] text-white rounded font-bold uppercase tracking-tighter">
                                                                Retard
                                                            </span>
                                                        )}
                                                    </span>
                                                    {task.notes && (
                                                        <span className="text-xs text-gray-500 mt-1 italic line-clamp-1 max-w-xs" title={task.notes}>
                                                            {task.notes}
                                                        </span>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="p-4 text-sm text-gray-600">
                                                {relatedCase ? (
                                                    <div className="flex flex-col">
                                                        <span className="font-medium">{relatedCase.name}</span>
                                                        <span className="text-xs text-gray-400">{relatedCase.client}</span>
                                                    </div>
                                                ) : 'N/A'}
                                            </td>
                                            <td className="p-4 text-sm">
                                                <span className={`font-medium ${late ? 'text-red-600 font-bold' : 'text-gray-600'}`}>
                                                    {new Date(task.dueDate).toLocaleDateString('fr-FR')}
                                                </span>
                                            </td>
                                            <td className="p-4 text-sm text-gray-600">{task.lawyer}</td>
                                            <td className="p-4">
                                                <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${getStatusClass(task.status)}`}>
                                                    {task.status}
                                                </span>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={5} className="p-12 text-center">
                                        <div className="flex flex-col items-center justify-center space-y-3">
                                            <div className="bg-gray-50 p-4 rounded-full">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" />
                                                </svg>
                                            </div>
                                            <p className="text-gray-400 font-medium">
                                                {showOnlyOverdue ? "Félicitations ! Aucune tâche n'est en retard." : "Aucune tâche enregistrée."}
                                            </p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </PageContainer>
            <TaskModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={onAddTask} cases={cases} lawyers={lawyers} />
        </>
    );
};

