import React, { FC, useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    feedback?: 'positive' | 'negative' | null;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const initialAssistantMessage: Message = { 
        role: 'assistant', 
        content: "Bonjour ! Je suis l'assistant IA de KBB App. Je peux vous aider à analyser vos dossiers, résumer vos tâches ou répondre à vos questions sur vos clients. Comment puis-je vous aider aujourd'hui ?",
        feedback: null
    };

    const [messages, setMessages] = useState<Message[]>([initialAssistantMessage]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [copyFeedback, setCopyFeedback] = useState<number | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const suggestions = [
        "Résumé des dossiers en cours",
        "Quelles sont les tâches urgentes ?",
        "État des factures impayées",
        "Liste des clients par secteur",
        "Préparer un mémo pour une audience"
    ];

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isLoading]);

    const handleClearChat = () => {
        if (window.confirm("Voulez-vous vraiment effacer l'historique de cette conversation ?")) {
            setMessages([initialAssistantMessage]);
        }
    };

    const handleCopy = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopyFeedback(index);
        setTimeout(() => setCopyFeedback(null), 2000);
    };

    const handleFeedback = (index: number, type: 'positive' | 'negative') => {
        setMessages(prev => prev.map((msg, i) => 
            i === index ? { ...msg, feedback: msg.feedback === type ? null : type } : msg
        ));
    };

    const handleSend = async (e?: React.FormEvent, overrideInput?: string) => {
        if (e) e.preventDefault();
        const messageToSend = (overrideInput || input).trim();
        if (!messageToSend || isLoading) return;

        setInput('');
        setMessages(prev => [...prev, { role: 'user', content: messageToSend }]);
        setIsLoading(true);

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

            const context = `
                Tu es l'assistant intelligent du cabinet d'avocats KBB. 
                Voici l'état actuel des données du cabinet :
                - Clients (${clients.length}) : ${clients.map(c => c.name).join(', ')}
                - Dossiers (${cases.length}) : ${cases.map(c => `${c.name} (ID: ${c.id}, Client: ${c.client}, Statut: ${c.status})`).join(' | ')}
                - Tâches : ${tasks.map(t => `${t.name} pour ${t.lawyer}, échéance ${t.dueDate}, statut ${t.status}`).join(' | ')}
                - Factures : ${invoices.length} factures (Total dû: ${invoices.reduce((acc, inv) => acc + (inv.totalAmount - inv.paidAmount), 0)}€).

                RÈGLES DE RÉPONSE :
                1. Réponds de manière professionnelle et concise.
                2. UTILISE LE FORMAT MARKDOWN pour les tableaux et le code si nécessaire.
                3. Si on te demande un résumé ou une liste, utilise des puces ou un tableau Markdown.
                4. Garde un ton d'assistant juridique expert.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    ...messages.filter(m => m.role !== 'assistant' || m !== initialAssistantMessage).map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: messageToSend }] }
                ],
                config: {
                    systemInstruction: context,
                    temperature: 0.7,
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse, feedback: null }]);
        } catch (error) {
            console.error("AI Error:", error);
            setMessages(prev => [...prev, { role: 'assistant', content: "Une erreur est survenue. Veuillez vérifier votre clé API ou votre connexion.", feedback: null }]);
        } finally {
            setIsLoading(false);
        }
    };

    // Helper to render basic markdown-ish tables and code blocks
    const renderContent = (content: string) => {
        // Simple check for potential markdown table
        if (content.includes('|') && content.includes('\n|')) {
            const lines = content.split('\n');
            return (
                <div className="overflow-x-auto my-2 border rounded-lg bg-white/50">
                    <table className="min-w-full divide-y divide-gray-200 text-sm">
                        <tbody className="divide-y divide-gray-200">
                            {lines.map((line, i) => {
                                if (!line.trim().startsWith('|')) return <p key={i} className="px-4 py-1">{line}</p>;
                                const cells = line.split('|').filter(c => c.trim() !== '' || line.indexOf('|') !== line.lastIndexOf('|'));
                                if (line.includes('---')) return null; // Skip markdown separator
                                return (
                                    <tr key={i} className={i === 0 ? "bg-gray-50 font-bold" : ""}>
                                        {cells.map((cell, j) => (
                                            <td key={j} className="px-4 py-2 whitespace-nowrap">{cell.trim()}</td>
                                        ))}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            );
        }
        return <p className="text-sm whitespace-pre-wrap leading-relaxed">{content}</p>;
    };

    return (
        <div className="flex flex-col h-full max-h-screen">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-3xl font-bold text-gray-800 flex items-center">
                    <span className="bg-indigo-600 text-white p-2 rounded-lg mr-3 shadow-lg shadow-indigo-200">
                        <AIIcon />
                    </span>
                    Assistant IA KBB
                </h1>
                <div className="flex items-center space-x-3">
                    <button 
                        onClick={handleClearChat}
                        className="flex items-center space-x-2 px-3 py-1.5 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-100"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                        <span>Réinitialiser</span>
                    </button>
                    <div className="text-xs font-medium text-gray-400 bg-white px-3 py-1.5 rounded-full shadow-sm border border-gray-100">
                        Modèle : Gemini 3 Flash
                    </div>
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-xl flex-1 flex flex-col overflow-hidden border border-gray-100">
                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50 custom-scrollbar">
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`group relative flex max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`flex-shrink-0 h-10 w-10 rounded-xl flex items-center justify-center font-bold shadow-sm transition-transform group-hover:scale-105 ${
                                    msg.role === 'user' ? 'bg-indigo-600 text-white ml-3' : 'bg-white text-indigo-600 mr-3 border border-indigo-100'
                                }`}>
                                    {msg.role === 'user' ? 'U' : 'IA'}
                                </div>
                                <div className={`relative px-5 py-3 rounded-2xl shadow-sm border ${
                                    msg.role === 'user' 
                                    ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                                    : 'bg-white text-gray-800 border-gray-200 rounded-tl-none'
                                }`}>
                                    {renderContent(msg.content)}

                                    {msg.role === 'assistant' && (
                                        <div className="absolute -right-12 top-0 flex flex-col space-y-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={() => handleCopy(msg.content, idx)}
                                                className="p-1.5 text-gray-400 hover:text-indigo-600 bg-white border border-gray-100 rounded-lg shadow-sm"
                                                title="Copier la réponse"
                                            >
                                                {copyFeedback === idx ? (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                    </svg>
                                                ) : (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                                                    </svg>
                                                )}
                                            </button>
                                            <div className="flex flex-col space-y-1">
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'positive')}
                                                    className={`p-1.5 border border-gray-100 rounded-lg shadow-sm transition-colors ${msg.feedback === 'positive' ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-gray-400 hover:text-green-600'}`}
                                                    title="Réponse utile"
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 10h4.708c.944 0 1.708.764 1.708 1.708 0 .178-.027.354-.08.524l-2.09 6.556A1.708 1.708 0 0116.635 20H7V10l3.745-7.489c.355-.71 1.258-.87 1.826-.32l2.429 2.429V10zM7 10H3v10h4V10z" />
                                                    </svg>
                                                </button>
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'negative')}
                                                    className={`p-1.5 border border-gray-100 rounded-lg shadow-sm transition-colors ${msg.feedback === 'negative' ? 'bg-red-50 text-red-600 border-red-200' : 'bg-white text-gray-400 hover:text-red-600'}`}
                                                    title="Réponse peu pertinente"
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 14H5.292c-.944 0-1.708-.764-1.708-1.708 0-.178.027-.354.08-.524l2.09-6.556A1.708 1.708 0 017.365 4H17v10l-3.745 7.489c-.355.71-1.258.87-1.826.32l-2.429-2.429V14zM17 14h4V4h-4v10z" />
                                                    </svg>
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className="flex items-center space-x-3 bg-white px-5 py-3 rounded-2xl rounded-tl-none border border-gray-200 shadow-sm">
                                <div className="flex space-x-1">
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                                </div>
                                <span className="text-xs font-medium text-gray-500">L'IA prépare votre réponse...</span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Suggestions and Input Area */}
                <div className="p-4 bg-white border-t border-gray-100">
                    <div className="max-w-4xl mx-auto mb-4 overflow-x-auto hide-scrollbar flex space-x-2 pb-1">
                        {suggestions.map((suggestion, i) => (
                            <button
                                key={i}
                                onClick={() => handleSend(undefined, suggestion)}
                                className="whitespace-nowrap px-4 py-1.5 text-xs font-medium bg-indigo-50 text-indigo-700 rounded-full hover:bg-indigo-100 border border-indigo-100 transition-colors"
                            >
                                {suggestion}
                            </button>
                        ))}
                    </div>

                    <form onSubmit={handleSend} className="relative max-w-4xl mx-auto flex items-center space-x-3">
                        <input
                            type="text"
                            placeholder="Posez une question sur vos dossiers ou demandez un conseil juridique..."
                            className="flex-1 p-4 pr-16 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all bg-gray-50 hover:bg-white text-sm"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-2 bg-indigo-600 text-white p-2.5 rounded-xl hover:bg-indigo-700 transition duration-300 shadow-lg shadow-indigo-200 disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                            </svg>
                        </button>
                    </form>
                    <p className="text-center text-[10px] text-gray-400 mt-2 font-medium tracking-wide">
                        L'IA KBB peut faire des erreurs. Vérifiez les points de droit importants.
                    </p>
                </div>
            </div>

            <style>{`
                .hide-scrollbar::-webkit-scrollbar { display: none; }
                .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
            `}</style>
        </div>
    );
};

export default AIAssistantPage;

import React, { FC, useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';
import { usePersistentState } from '../hooks/usePersistentState';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    feedback?: 'positive' | 'negative' | null;
}

interface Conversation {
    id: string;
    title: string;
    messages: Message[];
    timestamp: number;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const initialAssistantMessage: Message = { 
        role: 'assistant', 
        content: "Bonjour ! Je suis l'assistant IA de KBB App. Je peux vous aider à analyser vos dossiers, résumer vos tâches ou répondre à vos questions sur vos clients. Comment puis-je vous aider aujourd'hui ?",
        feedback: null
    };

    // History management
    const [conversations, setConversations] = usePersistentState<Conversation[]>('kbb_ai_history', []);
    const [currentConvId, setCurrentConvId] = useState<string | null>(null);

    // Current chat state
    const [messages, setMessages] = useState<Message[]>([initialAssistantMessage]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [copyFeedback, setCopyFeedback] = useState<number | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const suggestions = [
        "Résumé des dossiers en cours",
        "Quelles sont les tâches urgentes ?",
        "État des factures impayées",
        "Liste des clients par secteur",
        "Préparer un mémo pour une audience"
    ];

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isLoading]);

    // Update history when messages change
    useEffect(() => {
        if (currentConvId && messages.length > 1) {
            setConversations(prev => prev.map(conv => 
                conv.id === currentConvId ? { ...conv, messages: messages } : conv
            ));
        }
    }, [messages]);

    const handleNewChat = () => {
        setCurrentConvId(null);
        setMessages([initialAssistantMessage]);
        setInput('');
    };

    const handleSelectConversation = (conv: Conversation) => {
        setCurrentConvId(conv.id);
        setMessages(conv.messages);
    };

    const handleDeleteConversation = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (window.confirm("Supprimer cette conversation ?")) {
            setConversations(prev => prev.filter(c => c.id !== id));
            if (currentConvId === id) {
                handleNewChat();
            }
        }
    };

    const handleClearChat = () => {
        if (window.confirm("Voulez-vous vraiment effacer l'historique de cette conversation ?")) {
            setMessages([initialAssistantMessage]);
            if (currentConvId) {
                setConversations(prev => prev.filter(c => c.id !== currentConvId));
                setCurrentConvId(null);
            }
        }
    };

    const handleCopy = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopyFeedback(index);
        setTimeout(() => setCopyFeedback(null), 2000);
    };

    const handleFeedback = (index: number, type: 'positive' | 'negative') => {
        setMessages(prev => prev.map((msg, i) => 
            i === index ? { ...msg, feedback: msg.feedback === type ? null : type } : msg
        ));
    };

    const handleSend = async (e?: React.FormEvent, overrideInput?: string) => {
        if (e) e.preventDefault();
        const messageToSend = (overrideInput || input).trim();
        if (!messageToSend || isLoading) return;

        let activeId = currentConvId;
        const newMsg: Message = { role: 'user', content: messageToSend };
        const updatedMessages = [...messages, newMsg];

        // Create new conversation if needed
        if (!activeId) {
            const newId = Date.now().toString();
            const newConv: Conversation = {
                id: newId,
                title: messageToSend.length > 30 ? messageToSend.substring(0, 30) + '...' : messageToSend,
                messages: updatedMessages,
                timestamp: Date.now()
            };
            setConversations(prev => [newConv, ...prev]);
            setCurrentConvId(newId);
            activeId = newId;
        }

        setInput('');
        setMessages(updatedMessages);
        setIsLoading(true);

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

            const context = `
                Tu es l'assistant intelligent du cabinet d'avocats KBB. 
                Voici l'état actuel des données du cabinet :
                - Clients (${clients.length}) : ${clients.map(c => c.name).join(', ')}
                - Dossiers (${cases.length}) : ${cases.map(c => `${c.name} (ID: ${c.id}, Client: ${c.client}, Statut: ${c.status})`).join(' | ')}
                - Tâches : ${tasks.map(t => `${t.name} pour ${t.lawyer}, échéance ${t.dueDate}, statut ${t.status}`).join(' | ')}
                - Factures : ${invoices.length} factures (Total dû: ${invoices.reduce((acc, inv) => acc + (inv.totalAmount - inv.paidAmount), 0)}€).

                RÈGLES DE RÉPONSE :
                1. Réponds de manière professionnelle et concise.
                2. UTILISE LE FORMAT MARKDOWN pour les tableaux et le code si nécessaire.
                3. Si on te demande un résumé ou une liste, utilise des puces ou un tableau Markdown.
                4. Garde un ton d'assistant juridique expert.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    ...messages.filter(m => m.role !== 'assistant' || m !== initialAssistantMessage).map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: messageToSend }] }
                ],
                config: {
                    systemInstruction: context,
                    temperature: 0.7,
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse, feedback: null }]);
        } catch (error) {
            console.error("AI Error:", error);
            setMessages(prev => [...prev, { role: 'assistant', content: "Une erreur est survenue. Veuillez vérifier votre clé API ou votre connexion.", feedback: null }]);
        } finally {
            setIsLoading(false);
        }
    };

    const renderContent = (content: string) => {
        if (content.includes('|') && content.includes('\n|')) {
            const lines = content.split('\n');
            return (
                <div className="overflow-x-auto my-2 border rounded-lg bg-white/50">
                    <table className="min-w-full divide-y divide-gray-200 text-sm">
                        <tbody className="divide-y divide-gray-200">
                            {lines.map((line, i) => {
                                if (!line.trim().startsWith('|')) return <p key={i} className="px-4 py-1">{line}</p>;
                                const cells = line.split('|').filter(c => c.trim() !== '' || line.indexOf('|') !== line.lastIndexOf('|'));
                                if (line.includes('---')) return null;
                                return (
                                    <tr key={i} className={i === 0 ? "bg-gray-50 font-bold" : ""}>
                                        {cells.map((cell, j) => (
                                            <td key={j} className="px-4 py-2 whitespace-nowrap">{cell.trim()}</td>
                                        ))}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            );
        }
        return <p className="text-sm whitespace-pre-wrap leading-relaxed">{content}</p>;
    };

    return (
        <div className="flex h-full max-h-screen -m-8"> {/* Negative margin to use full dashboard space */}
            {/* Sidebar History */}
            <div className="w-72 bg-slate-100 border-r border-slate-200 flex flex-col h-full overflow-hidden">
                <div className="p-4 border-b border-slate-200 bg-white">
                    <button 
                        onClick={handleNewChat}
                        className="w-full flex items-center justify-center space-x-2 bg-indigo-600 text-white py-2.5 rounded-xl hover:bg-indigo-700 transition shadow-sm font-semibold text-sm"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                        <span>Nouvelle Discussion</span>
                    </button>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-2">
                    <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-3 px-2">Historique des discussions</h2>
                    {conversations.length === 0 ? (
                        <p className="text-xs text-slate-400 text-center py-10 px-4 italic">Aucune conversation passée</p>
                    ) : (
                        conversations.map(conv => (
                            <div 
                                key={conv.id}
                                onClick={() => handleSelectConversation(conv)}
                                className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                                    currentConvId === conv.id 
                                    ? 'bg-white border-indigo-200 shadow-sm text-indigo-700' 
                                    : 'border-transparent hover:bg-slate-200 text-slate-600'
                                }`}
                            >
                                <div className="flex items-center space-x-3 truncate">
                                    <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 flex-shrink-0 ${currentConvId === conv.id ? 'text-indigo-500' : 'text-slate-400'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                                    </svg>
                                    <div className="flex flex-col truncate">
                                        <span className="text-sm font-medium truncate">{conv.title}</span>
                                        <span className="text-[10px] opacity-60">
                                            {new Date(conv.timestamp).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' })}
                                        </span>
                                    </div>
                                </div>
                                <button 
                                    onClick={(e) => handleDeleteConversation(conv.id, e)}
                                    className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-600 text-slate-400 transition"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                    </svg>
                                </button>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* Chat Content */}
            <div className="flex-1 flex flex-col min-w-0 bg-white">
                <div className="flex justify-between items-center p-6 border-b border-slate-100">
                    <h1 className="text-2xl font-bold text-gray-800 flex items-center">
                        <span className="bg-indigo-600 text-white p-2 rounded-lg mr-3 shadow-lg shadow-indigo-200">
                            <AIIcon />
                        </span>
                        Assistant IA KBB
                    </h1>
                    <div className="flex items-center space-x-3">
                        <button 
                            onClick={handleClearChat}
                            className="flex items-center space-x-2 px-3 py-1.5 text-xs font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                            <span>Réinitialiser</span>
                        </button>
                        <div className="text-[10px] font-bold text-slate-400 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100 uppercase tracking-wider">
                            Gemini 3 Flash
                        </div>
                    </div>
                </div>

                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30 custom-scrollbar">
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`group relative flex max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`flex-shrink-0 h-9 w-9 rounded-xl flex items-center justify-center font-bold shadow-sm transition-transform group-hover:scale-105 ${
                                    msg.role === 'user' ? 'bg-indigo-600 text-white ml-3' : 'bg-white text-indigo-600 mr-3 border border-indigo-100'
                                }`}>
                                    {msg.role === 'user' ? 'U' : 'IA'}
                                </div>
                                <div className={`relative px-5 py-3 rounded-2xl shadow-sm border ${
                                    msg.role === 'user' 
                                    ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                                    : 'bg-white text-gray-800 border-gray-200 rounded-tl-none'
                                }`}>
                                    {renderContent(msg.content)}

                                    {msg.role === 'assistant' && (
                                        <div className="absolute -right-12 top-0 flex flex-col space-y-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={() => handleCopy(msg.content, idx)}
                                                className="p-1.5 text-gray-400 hover:text-indigo-600 bg-white border border-gray-100 rounded-lg shadow-sm"
                                            >
                                                {copyFeedback === idx ? (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                    </svg>
                                                ) : (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                                                    </svg>
                                                )}
                                            </button>
                                            <div className="flex flex-col space-y-1">
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'positive')}
                                                    className={`p-1.5 border border-gray-100 rounded-lg shadow-sm transition-colors ${msg.feedback === 'positive' ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-gray-400 hover:text-green-600'}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 10h4.708c.944 0 1.708.764 1.708 1.708 0 .178-.027.354-.08.524l-2.09 6.556A1.708 1.708 0 0116.635 20H7V10l3.745-7.489c.355-.71 1.258-.87 1.826-.32l2.429 2.429V10zM7 10H3v10h4V10z" />
                                                    </svg>
                                                </button>
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'negative')}
                                                    className={`p-1.5 border border-gray-100 rounded-lg shadow-sm transition-colors ${msg.feedback === 'negative' ? 'bg-red-50 text-red-600 border-red-200' : 'bg-white text-gray-400 hover:text-red-600'}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 14H5.292c-.944 0-1.708-.764-1.708-1.708 0-.178.027-.354.08-.524l2.09-6.556A1.708 1.708 0 017.365 4H17v10l-3.745 7.489c-.355.71-1.258.87-1.826.32l-2.429-2.429V14zM17 14h4V4h-4v10z" />
                                                    </svg>
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className="flex items-center space-x-3 bg-white px-5 py-3 rounded-2xl rounded-tl-none border border-gray-200 shadow-sm">
                                <div className="flex space-x-1">
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                                </div>
                                <span className="text-xs font-medium text-gray-500 italic">Analyse en cours...</span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className="p-6 bg-white border-t border-slate-100">
                    <div className="max-w-4xl mx-auto mb-4 overflow-x-auto hide-scrollbar flex space-x-2 pb-2">
                        {suggestions.map((suggestion, i) => (
                            <button
                                key={i}
                                onClick={() => handleSend(undefined, suggestion)}
                                className="whitespace-nowrap px-3 py-1.5 text-[11px] font-bold bg-slate-50 text-slate-600 rounded-full hover:bg-indigo-50 hover:text-indigo-600 border border-slate-200 transition-all uppercase tracking-tight"
                            >
                                {suggestion}
                            </button>
                        ))}
                    </div>

                    <form onSubmit={handleSend} className="relative max-w-4xl mx-auto">
                        <input
                            type="text"
                            placeholder="Interrogez l'IA sur vos dossiers ou clients..."
                            className="w-full p-4 pr-16 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all bg-slate-50 hover:bg-white text-sm"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-2 top-2 bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 disabled:opacity-50"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                            </svg>
                        </button>
                    </form>
                    <p className="text-center text-[10px] text-slate-400 mt-3 font-medium tracking-wide">
                        L'intelligence artificielle peut générer des erreurs. Veuillez vérifier les informations clés.
                    </p>
                </div>
            </div>

            <style>{`
                .hide-scrollbar::-webkit-scrollbar { display: none; }
                .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
            `}</style>
        </div>
    );
};

export default AIAssistantPage;

import React, { FC, useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';
import { usePersistentState } from '../hooks/usePersistentState';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    feedback?: 'positive' | 'negative' | null;
}

interface Conversation {
    id: string;
    title: string;
    messages: Message[];
    timestamp: number;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const initialAssistantMessage: Message = { 
        role: 'assistant', 
        content: "Bonjour ! Je suis l'assistant IA de KBB App. Je peux vous aider à analyser vos dossiers, résumer vos tâches ou répondre à vos questions sur vos clients. Comment puis-je vous aider aujourd'hui ?",
        feedback: null
    };

    // History and UI settings management
    const [conversations, setConversations] = usePersistentState<Conversation[]>('kbb_ai_history', []);
    const [isDarkMode, setIsDarkMode] = usePersistentState<boolean>('kbb_ai_dark_mode', false);
    const [currentConvId, setCurrentConvId] = useState<string | null>(null);

    // Current chat state
    const [messages, setMessages] = useState<Message[]>([initialAssistantMessage]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [copyFeedback, setCopyFeedback] = useState<number | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const suggestions = [
        "Résumé des dossiers en cours",
        "Quelles sont les tâches urgentes ?",
        "État des factures impayées",
        "Liste des clients par secteur",
        "Préparer un mémo pour une audience"
    ];

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isLoading]);

    // Update history when messages change
    useEffect(() => {
        if (currentConvId && messages.length > 1) {
            setConversations(prev => prev.map(conv => 
                conv.id === currentConvId ? { ...conv, messages: messages } : conv
            ));
        }
    }, [messages]);

    const handleNewChat = () => {
        setCurrentConvId(null);
        setMessages([initialAssistantMessage]);
        setInput('');
    };

    const handleSelectConversation = (conv: Conversation) => {
        setCurrentConvId(conv.id);
        setMessages(conv.messages);
    };

    const handleDeleteConversation = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (window.confirm("Supprimer cette conversation ?")) {
            setConversations(prev => prev.filter(c => c.id !== id));
            if (currentConvId === id) {
                handleNewChat();
            }
        }
    };

    const handleClearChat = () => {
        if (window.confirm("Voulez-vous vraiment effacer l'historique de cette conversation ?")) {
            setMessages([initialAssistantMessage]);
            if (currentConvId) {
                setConversations(prev => prev.filter(c => c.id !== currentConvId));
                setCurrentConvId(null);
            }
        }
    };

    const handleCopy = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopyFeedback(index);
        setTimeout(() => setCopyFeedback(null), 2000);
    };

    const handleFeedback = (index: number, type: 'positive' | 'negative') => {
        setMessages(prev => prev.map((msg, i) => 
            i === index ? { ...msg, feedback: msg.feedback === type ? null : type } : msg
        ));
    };

    const handleSend = async (e?: React.FormEvent, overrideInput?: string) => {
        if (e) e.preventDefault();
        const messageToSend = (overrideInput || input).trim();
        if (!messageToSend || isLoading) return;

        let activeId = currentConvId;
        const newMsg: Message = { role: 'user', content: messageToSend };
        const updatedMessages = [...messages, newMsg];

        if (!activeId) {
            const newId = Date.now().toString();
            const newConv: Conversation = {
                id: newId,
                title: messageToSend.length > 30 ? messageToSend.substring(0, 30) + '...' : messageToSend,
                messages: updatedMessages,
                timestamp: Date.now()
            };
            setConversations(prev => [newConv, ...prev]);
            setCurrentConvId(newId);
            activeId = newId;
        }

        setInput('');
        setMessages(updatedMessages);
        setIsLoading(true);

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

            const context = `
                Tu es l'assistant intelligent du cabinet d'avocats KBB. 
                Voici l'état actuel des données du cabinet :
                - Clients (${clients.length}) : ${clients.map(c => c.name).join(', ')}
                - Dossiers (${cases.length}) : ${cases.map(c => `${c.name} (ID: ${c.id}, Client: ${c.client}, Statut: ${c.status})`).join(' | ')}
                - Tâches : ${tasks.map(t => `${t.name} pour ${t.lawyer}, échéance ${t.dueDate}, statut ${t.status}`).join(' | ')}
                - Factures : ${invoices.length} factures (Total dû: ${invoices.reduce((acc, inv) => acc + (inv.totalAmount - inv.paidAmount), 0)}€).

                RÈGLES DE RÉPONSE :
                1. Réponds de manière professionnelle et concise.
                2. UTILISE LE FORMAT MARKDOWN pour les tableaux et le code si nécessaire.
                3. Si on te demande un résumé ou une liste, utilise des puces ou un tableau Markdown.
                4. Garde un ton d'assistant juridique expert.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    ...messages.filter(m => m.role !== 'assistant' || m !== initialAssistantMessage).map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: messageToSend }] }
                ],
                config: {
                    systemInstruction: context,
                    temperature: 0.7,
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse, feedback: null }]);
        } catch (error) {
            console.error("AI Error:", error);
            setMessages(prev => [...prev, { role: 'assistant', content: "Une erreur est survenue. Veuillez vérifier votre clé API ou votre connexion.", feedback: null }]);
        } finally {
            setIsLoading(false);
        }
    };

    const renderContent = (content: string) => {
        if (content.includes('|') && content.includes('\n|')) {
            const lines = content.split('\n');
            return (
                <div className={`overflow-x-auto my-2 border rounded-lg ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-white/50 border-gray-200'}`}>
                    <table className={`min-w-full divide-y text-sm ${isDarkMode ? 'divide-gray-700 text-gray-200' : 'divide-gray-200 text-gray-800'}`}>
                        <tbody className={`divide-y ${isDarkMode ? 'divide-gray-700' : 'divide-gray-200'}`}>
                            {lines.map((line, i) => {
                                if (!line.trim().startsWith('|')) return <p key={i} className="px-4 py-1">{line}</p>;
                                const cells = line.split('|').filter(c => c.trim() !== '' || line.indexOf('|') !== line.lastIndexOf('|'));
                                if (line.includes('---')) return null;
                                return (
                                    <tr key={i} className={i === 0 ? (isDarkMode ? "bg-gray-700 font-bold" : "bg-gray-50 font-bold") : ""}>
                                        {cells.map((cell, j) => (
                                            <td key={j} className="px-4 py-2 whitespace-nowrap">{cell.trim()}</td>
                                        ))}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            );
        }
        return <p className="text-sm whitespace-pre-wrap leading-relaxed">{content}</p>;
    };

    return (
        <div className={`flex h-full max-h-screen -m-8 transition-colors duration-300 ${isDarkMode ? 'bg-gray-950 text-gray-100' : 'bg-white text-gray-900'}`}>
            {/* Sidebar History */}
            <div className={`w-72 border-r flex flex-col h-full overflow-hidden transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-slate-100 border-slate-200'}`}>
                <div className={`p-4 border-b transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-white border-slate-200'}`}>
                    <button 
                        onClick={handleNewChat}
                        className="w-full flex items-center justify-center space-x-2 bg-indigo-600 text-white py-2.5 rounded-xl hover:bg-indigo-700 transition shadow-sm font-semibold text-sm"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                        <span>Nouvelle Discussion</span>
                    </button>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-2">
                    <h2 className={`text-[11px] font-bold uppercase tracking-widest mb-3 px-2 ${isDarkMode ? 'text-gray-500' : 'text-slate-400'}`}>Historique</h2>
                    {conversations.length === 0 ? (
                        <p className={`text-xs text-center py-10 px-4 italic ${isDarkMode ? 'text-gray-600' : 'text-slate-400'}`}>Aucune conversation passée</p>
                    ) : (
                        conversations.map(conv => (
                            <div 
                                key={conv.id}
                                onClick={() => handleSelectConversation(conv)}
                                className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                                    currentConvId === conv.id 
                                    ? (isDarkMode ? 'bg-gray-800 border-indigo-500 text-indigo-400' : 'bg-white border-indigo-200 shadow-sm text-indigo-700') 
                                    : (isDarkMode ? 'border-transparent hover:bg-gray-800 text-gray-400' : 'border-transparent hover:bg-slate-200 text-slate-600')
                                }`}
                            >
                                <div className="flex items-center space-x-3 truncate">
                                    <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 flex-shrink-0 ${currentConvId === conv.id ? 'text-indigo-500' : (isDarkMode ? 'text-gray-600' : 'text-slate-400')}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                                    </svg>
                                    <div className="flex flex-col truncate">
                                        <span className="text-sm font-medium truncate">{conv.title}</span>
                                        <span className="text-[10px] opacity-60">
                                            {new Date(conv.timestamp).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' })}
                                        </span>
                                    </div>
                                </div>
                                <button 
                                    onClick={(e) => handleDeleteConversation(conv.id, e)}
                                    className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-600 text-slate-400 transition"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                    </svg>
                                </button>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* Chat Content */}
            <div className={`flex-1 flex flex-col min-w-0 transition-colors ${isDarkMode ? 'bg-gray-950' : 'bg-white'}`}>
                <div className={`flex justify-between items-center p-6 border-b transition-colors ${isDarkMode ? 'border-gray-800' : 'border-slate-100'}`}>
                    <h1 className={`text-2xl font-bold flex items-center ${isDarkMode ? 'text-gray-100' : 'text-gray-800'}`}>
                        <span className="bg-indigo-600 text-white p-2 rounded-lg mr-3 shadow-lg shadow-indigo-200">
                            <AIIcon />
                        </span>
                        Assistant IA KBB
                    </h1>
                    <div className="flex items-center space-x-3">
                        <button 
                            onClick={() => setIsDarkMode(!isDarkMode)}
                            className={`p-2 rounded-lg transition-colors border ${isDarkMode ? 'bg-gray-800 border-gray-700 text-yellow-400 hover:bg-gray-700' : 'bg-slate-50 border-slate-200 text-slate-600 hover:bg-slate-100'}`}
                            title={isDarkMode ? "Passer au mode clair" : "Passer au mode sombre"}
                        >
                            {isDarkMode ? (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707-.707m12.728 0A9 9 0 115.636 5.636m12.728 12.728L5.636 5.636" />
                                </svg>
                            ) : (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                                </svg>
                            )}
                        </button>
                        <button 
                            onClick={handleClearChat}
                            className={`flex items-center space-x-2 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${isDarkMode ? 'text-red-400 hover:bg-red-900/20' : 'text-red-600 hover:bg-red-50'}`}
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                            <span>Réinitialiser</span>
                        </button>
                    </div>
                </div>

                {/* Messages Area */}
                <div className={`flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar transition-colors ${isDarkMode ? 'bg-gray-900/50' : 'bg-slate-50/30'}`}>
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`group relative flex max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`flex-shrink-0 h-9 w-9 rounded-xl flex items-center justify-center font-bold shadow-sm transition-transform group-hover:scale-105 ${
                                    msg.role === 'user' ? 'bg-indigo-600 text-white ml-3' : (isDarkMode ? 'bg-gray-800 text-indigo-400 mr-3 border border-gray-700' : 'bg-white text-indigo-600 mr-3 border border-indigo-100')
                                }`}>
                                    {msg.role === 'user' ? 'U' : 'IA'}
                                </div>
                                <div className={`relative px-5 py-3 rounded-2xl shadow-sm border transition-colors ${
                                    msg.role === 'user' 
                                    ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                                    : (isDarkMode ? 'bg-gray-800 text-gray-200 border-gray-700 rounded-tl-none' : 'bg-white text-gray-800 border-gray-200 rounded-tl-none')
                                }`}>
                                    {renderContent(msg.content)}

                                    {msg.role === 'assistant' && (
                                        <div className="absolute -right-12 top-0 flex flex-col space-y-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={() => handleCopy(msg.content, idx)}
                                                className={`p-1.5 border rounded-lg shadow-sm transition-colors ${isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-indigo-400' : 'bg-white text-gray-400 border-gray-100 hover:text-indigo-600'}`}
                                            >
                                                {copyFeedback === idx ? (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                    </svg>
                                                ) : (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2.000a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                                                    </svg>
                                                )}
                                            </button>
                                            <div className="flex flex-col space-y-1">
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'positive')}
                                                    className={`p-1.5 border rounded-lg shadow-sm transition-colors ${msg.feedback === 'positive' ? 'bg-green-500/10 text-green-500 border-green-500/20' : (isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-green-500' : 'bg-white text-gray-400 border-gray-100 hover:text-green-600')}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 10h4.708c.944 0 1.708.764 1.708 1.708 0 .178-.027.354-.08.524l-2.09 6.556A1.708 1.708 0 0116.635 20H7V10l3.745-7.489c.355-.71 1.258-.87 1.826-.32l2.429 2.429V10zM7 10H3v10h4V10z" />
                                                    </svg>
                                                </button>
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'negative')}
                                                    className={`p-1.5 border rounded-lg shadow-sm transition-colors ${msg.feedback === 'negative' ? 'bg-red-500/10 text-red-500 border-red-500/20' : (isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-red-500' : 'bg-white text-gray-400 border-gray-100 hover:text-red-600')}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 14H5.292c-.944 0-1.708-.764-1.708-1.708 0-.178.027-.354.08-.524l2.09-6.556A1.708 1.708 0 017.365 4H17v10l-3.745 7.489c-.355.71-1.258.87-1.826.32l-2.429-2.429V14zM17 14h4V4h-4v10z" />
                                                    </svg>
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className={`flex items-center space-x-3 px-5 py-3 rounded-2xl rounded-tl-none border shadow-sm transition-colors ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'}`}>
                                <div className="flex space-x-1">
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                                </div>
                                <span className={`text-xs font-medium italic ${isDarkMode ? 'text-gray-400' : 'text-gray-500'}`}>Analyse en cours...</span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className={`p-6 border-t transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-white border-slate-100'}`}>
                    <div className="max-w-4xl mx-auto mb-4 overflow-x-auto hide-scrollbar flex space-x-2 pb-2">
                        {suggestions.map((suggestion, i) => (
                            <button
                                key={i}
                                onClick={() => handleSend(undefined, suggestion)}
                                className={`whitespace-nowrap px-3 py-1.5 text-[11px] font-bold rounded-full border transition-all uppercase tracking-tight ${
                                    isDarkMode 
                                    ? 'bg-gray-800 text-gray-400 border-gray-700 hover:bg-indigo-900/30 hover:text-indigo-400 hover:border-indigo-500/50' 
                                    : 'bg-slate-50 text-slate-600 border-slate-200 hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-200'
                                }`}
                            >
                                {suggestion}
                            </button>
                        ))}
                    </div>

                    <form onSubmit={handleSend} className="relative max-w-4xl mx-auto">
                        <input
                            type="text"
                            placeholder="Interrogez l'IA sur vos dossiers ou clients..."
                            className={`w-full p-4 pr-16 border rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all text-sm ${
                                isDarkMode 
                                ? 'bg-gray-800 border-gray-700 text-gray-100 placeholder-gray-500 hover:bg-gray-700/50' 
                                : 'bg-slate-50 border-slate-200 text-gray-900 placeholder-slate-400 hover:bg-white'
                            }`}
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-2 top-2 bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 disabled:opacity-50"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                            </svg>
                        </button>
                    </form>
                    <p className={`text-center text-[10px] mt-3 font-medium tracking-wide ${isDarkMode ? 'text-gray-500' : 'text-slate-400'}`}>
                        L'intelligence artificielle peut générer des erreurs. Veuillez vérifier les informations clés.
                    </p>
                </div>
            </div>

            <style>{`
                .hide-scrollbar::-webkit-scrollbar { display: none; }
                .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
            `}</style>
        </div>
    );
};

export default AIAssistantPage;

import React, { FC, useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';
import { usePersistentState } from '../hooks/usePersistentState';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    feedback?: 'positive' | 'negative' | null;
}

interface Conversation {
    id: string;
    title: string;
    messages: Message[];
    timestamp: number;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const initialAssistantMessage: Message = { 
        role: 'assistant', 
        content: "Bonjour ! Je suis l'assistant IA de KBB App. Je peux vous aider à analyser vos dossiers, résumer vos tâches ou répondre à vos questions sur vos clients. Comment puis-je vous aider aujourd'hui ?",
        feedback: null
    };

    // History and UI settings management
    const [conversations, setConversations] = usePersistentState<Conversation[]>('kbb_ai_history', []);
    const [isDarkMode, setIsDarkMode] = usePersistentState<boolean>('kbb_ai_dark_mode', false);
    const [currentConvId, setCurrentConvId] = useState<string | null>(null);

    // Current chat state
    const [messages, setMessages] = useState<Message[]>([initialAssistantMessage]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [copyFeedback, setCopyFeedback] = useState<number | null>(null);
    const [errorMessage, setErrorMessage] = useState<string | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const suggestions = [
        "Résumé des dossiers en cours",
        "Quelles sont les tâches urgentes ?",
        "État des factures impayées",
        "Liste des clients par secteur",
        "Préparer un mémo pour une audience"
    ];

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isLoading]);

    // Handle error timeout
    useEffect(() => {
        if (errorMessage) {
            const timer = setTimeout(() => setErrorMessage(null), 6000);
            return () => clearTimeout(timer);
        }
    }, [errorMessage]);

    // Update history when messages change
    useEffect(() => {
        if (currentConvId && messages.length > 1) {
            setConversations(prev => prev.map(conv => 
                conv.id === currentConvId ? { ...conv, messages: messages } : conv
            ));
        }
    }, [messages]);

    const handleNewChat = () => {
        setCurrentConvId(null);
        setMessages([initialAssistantMessage]);
        setInput('');
    };

    const handleSelectConversation = (conv: Conversation) => {
        setCurrentConvId(conv.id);
        setMessages(conv.messages);
    };

    const handleDeleteConversation = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (window.confirm("Supprimer cette conversation ?")) {
            setConversations(prev => prev.filter(c => c.id !== id));
            if (currentConvId === id) {
                handleNewChat();
            }
        }
    };

    const handleClearChat = () => {
        if (window.confirm("Voulez-vous vraiment effacer l'historique de cette conversation ?")) {
            setMessages([initialAssistantMessage]);
            if (currentConvId) {
                setConversations(prev => prev.filter(c => c.id !== currentConvId));
                setCurrentConvId(null);
            }
        }
    };

    const handleCopy = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopyFeedback(index);
        setTimeout(() => setCopyFeedback(null), 2000);
    };

    const handleFeedback = (index: number, type: 'positive' | 'negative') => {
        setMessages(prev => prev.map((msg, i) => 
            i === index ? { ...msg, feedback: msg.feedback === type ? null : type } : msg
        ));
    };

    const handleSend = async (e?: React.FormEvent, overrideInput?: string) => {
        if (e) e.preventDefault();
        const messageToSend = (overrideInput || input).trim();
        if (!messageToSend || isLoading) return;

        let activeId = currentConvId;
        const newMsg: Message = { role: 'user', content: messageToSend };
        const updatedMessages = [...messages, newMsg];

        if (!activeId) {
            const newId = Date.now().toString();
            const newConv: Conversation = {
                id: newId,
                title: messageToSend.length > 30 ? messageToSend.substring(0, 30) + '...' : messageToSend,
                messages: updatedMessages,
                timestamp: Date.now()
            };
            setConversations(prev => [newConv, ...prev]);
            setCurrentConvId(newId);
            activeId = newId;
        }

        setInput('');
        setMessages(updatedMessages);
        setIsLoading(true);
        setErrorMessage(null);

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

            const context = `
                Tu es l'assistant intelligent du cabinet d'avocats KBB. 
                Voici l'état actuel des données du cabinet :
                - Clients (${clients.length}) : ${clients.map(c => c.name).join(', ')}
                - Dossiers (${cases.length}) : ${cases.map(c => `${c.name} (ID: ${c.id}, Client: ${c.client}, Statut: ${c.status})`).join(' | ')}
                - Tâches : ${tasks.map(t => `${t.name} pour ${t.lawyer}, échéance ${t.dueDate}, statut ${t.status}`).join(' | ')}
                - Factures : ${invoices.length} factures (Total dû: ${invoices.reduce((acc, inv) => acc + (inv.totalAmount - inv.paidAmount), 0)}€).

                RÈGLES DE RÉPONSE :
                1. Réponds de manière professionnelle et concise.
                2. UTILISE LE FORMAT MARKDOWN pour les tableaux et le code si nécessaire.
                3. Si on te demande un résumé ou une liste, utilise des puces ou un tableau Markdown.
                4. Garde un ton d'assistant juridique expert.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    ...messages.filter(m => m.role !== 'assistant' || m !== initialAssistantMessage).map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: messageToSend }] }
                ],
                config: {
                    systemInstruction: context,
                    temperature: 0.7,
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse, feedback: null }]);
        } catch (error) {
            console.error("AI Error:", error);
            setErrorMessage("Une erreur est survenue lors de la génération. Veuillez vérifier votre connexion ou votre clé API.");
        } finally {
            setIsLoading(false);
        }
    };

    const renderContent = (content: string) => {
        if (content.includes('|') && content.includes('\n|')) {
            const lines = content.split('\n');
            return (
                <div className={`overflow-x-auto my-2 border rounded-lg ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-white/50 border-gray-200'}`}>
                    <table className={`min-w-full divide-y text-sm ${isDarkMode ? 'divide-gray-700 text-gray-200' : 'divide-gray-200 text-gray-800'}`}>
                        <tbody className={`divide-y ${isDarkMode ? 'divide-gray-700' : 'divide-gray-200'}`}>
                            {lines.map((line, i) => {
                                if (!line.trim().startsWith('|')) return <p key={i} className="px-4 py-1">{line}</p>;
                                const cells = line.split('|').filter(c => c.trim() !== '' || line.indexOf('|') !== line.lastIndexOf('|'));
                                if (line.includes('---')) return null;
                                return (
                                    <tr key={i} className={i === 0 ? (isDarkMode ? "bg-gray-700 font-bold" : "bg-gray-50 font-bold") : ""}>
                                        {cells.map((cell, j) => (
                                            <td key={j} className="px-4 py-2 whitespace-nowrap">{cell.trim()}</td>
                                        ))}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            );
        }
        return <p className="text-sm whitespace-pre-wrap leading-relaxed">{content}</p>;
    };

    return (
        <div className={`flex h-full max-h-screen -m-8 transition-colors duration-300 ${isDarkMode ? 'bg-gray-950 text-gray-100' : 'bg-white text-gray-900'}`}>
            {/* Sidebar History */}
            <div className={`w-72 border-r flex flex-col h-full overflow-hidden transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-slate-100 border-slate-200'}`}>
                <div className={`p-4 border-b transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-white border-slate-200'}`}>
                    <button 
                        onClick={handleNewChat}
                        className="w-full flex items-center justify-center space-x-2 bg-indigo-600 text-white py-2.5 rounded-xl hover:bg-indigo-700 transition shadow-sm font-semibold text-sm"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                        <span>Nouvelle Discussion</span>
                    </button>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-2">
                    <h2 className={`text-[11px] font-bold uppercase tracking-widest mb-3 px-2 ${isDarkMode ? 'text-gray-500' : 'text-slate-400'}`}>Historique</h2>
                    {conversations.length === 0 ? (
                        <p className={`text-xs text-center py-10 px-4 italic ${isDarkMode ? 'text-gray-600' : 'text-slate-400'}`}>Aucune conversation passée</p>
                    ) : (
                        conversations.map(conv => (
                            <div 
                                key={conv.id}
                                onClick={() => handleSelectConversation(conv)}
                                className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                                    currentConvId === conv.id 
                                    ? (isDarkMode ? 'bg-gray-800 border-indigo-500 text-indigo-400' : 'bg-white border-indigo-200 shadow-sm text-indigo-700') 
                                    : (isDarkMode ? 'border-transparent hover:bg-gray-800 text-gray-400' : 'border-transparent hover:bg-slate-200 text-slate-600')
                                }`}
                            >
                                <div className="flex items-center space-x-3 truncate">
                                    <svg xmlns="http://www.w3.org/2000/svg" className={`h-4 w-4 flex-shrink-0 ${currentConvId === conv.id ? 'text-indigo-500' : (isDarkMode ? 'text-gray-600' : 'text-slate-400')}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                                    </svg>
                                    <div className="flex flex-col truncate">
                                        <span className="text-sm font-medium truncate">{conv.title}</span>
                                        <span className="text-[10px] opacity-60">
                                            {new Date(conv.timestamp).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' })}
                                        </span>
                                    </div>
                                </div>
                                <button 
                                    onClick={(e) => handleDeleteConversation(conv.id, e)}
                                    className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-600 text-slate-400 transition"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                    </svg>
                                </button>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* Chat Content */}
            <div className={`flex-1 flex flex-col min-w-0 transition-colors relative ${isDarkMode ? 'bg-gray-950' : 'bg-white'}`}>
                {/* Discrete Error Toast */}
                {errorMessage && (
                    <div className="absolute top-4 left-1/2 transform -translate-x-1/2 z-50 animate-fade-in-down w-full max-w-md px-4">
                        <div className={`flex items-center justify-between p-3 rounded-xl shadow-2xl border ${
                            isDarkMode ? 'bg-red-900/90 border-red-500 text-red-100' : 'bg-red-50 border-red-200 text-red-800'
                        }`}>
                            <div className="flex items-center space-x-3">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                                <span className="text-xs font-medium">{errorMessage}</span>
                            </div>
                            <button onClick={() => setErrorMessage(null)} className="ml-2 hover:opacity-70">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                </svg>
                            </button>
                        </div>
                    </div>
                )}

                <div className={`flex justify-between items-center p-6 border-b transition-colors ${isDarkMode ? 'border-gray-800' : 'border-slate-100'}`}>
                    <h1 className={`text-2xl font-bold flex items-center ${isDarkMode ? 'text-gray-100' : 'text-gray-800'}`}>
                        <span className="bg-indigo-600 text-white p-2 rounded-lg mr-3 shadow-lg shadow-indigo-200">
                            <AIIcon />
                        </span>
                        Assistant IA KBB
                    </h1>
                    <div className="flex items-center space-x-3">
                        <button 
                            onClick={() => setIsDarkMode(!isDarkMode)}
                            className={`p-2 rounded-lg transition-colors border ${isDarkMode ? 'bg-gray-800 border-gray-700 text-yellow-400 hover:bg-gray-700' : 'bg-slate-50 border-slate-200 text-slate-600 hover:bg-slate-100'}`}
                            title={isDarkMode ? "Passer au mode clair" : "Passer au mode sombre"}
                        >
                            {isDarkMode ? (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707-.707m12.728 0A9 9 0 115.636 5.636m12.728 12.728L5.636 5.636" />
                                </svg>
                            ) : (
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                                </svg>
                            )}
                        </button>
                        <button 
                            onClick={handleClearChat}
                            className={`flex items-center space-x-2 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${isDarkMode ? 'text-red-400 hover:bg-red-900/20' : 'text-red-600 hover:bg-red-50'}`}
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                            <span>Réinitialiser</span>
                        </button>
                    </div>
                </div>

                {/* Messages Area */}
                <div className={`flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar transition-colors ${isDarkMode ? 'bg-gray-900/50' : 'bg-slate-50/30'}`}>
                    {messages.map((msg, idx) => (
                        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`group relative flex max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`flex-shrink-0 h-9 w-9 rounded-xl flex items-center justify-center font-bold shadow-sm transition-transform group-hover:scale-105 ${
                                    msg.role === 'user' ? 'bg-indigo-600 text-white ml-3' : (isDarkMode ? 'bg-gray-800 text-indigo-400 mr-3 border border-gray-700' : 'bg-white text-indigo-600 mr-3 border border-indigo-100')
                                }`}>
                                    {msg.role === 'user' ? 'U' : 'IA'}
                                </div>
                                <div className={`relative px-5 py-3 rounded-2xl shadow-sm border transition-colors ${
                                    msg.role === 'user' 
                                    ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                                    : (isDarkMode ? 'bg-gray-800 text-gray-200 border-gray-700 rounded-tl-none' : 'bg-white text-gray-800 border-gray-200 rounded-tl-none')
                                }`}>
                                    {renderContent(msg.content)}

                                    {msg.role === 'assistant' && (
                                        <div className="absolute -right-12 top-0 flex flex-col space-y-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={() => handleCopy(msg.content, idx)}
                                                className={`p-1.5 border rounded-lg shadow-sm transition-colors ${isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-indigo-400' : 'bg-white text-gray-400 border-gray-100 hover:text-indigo-600'}`}
                                            >
                                                {copyFeedback === idx ? (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                    </svg>
                                                ) : (
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2.000a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                                                    </svg>
                                                )}
                                            </button>
                                            <div className="flex flex-col space-y-1">
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'positive')}
                                                    className={`p-1.5 border rounded-lg shadow-sm transition-colors ${msg.feedback === 'positive' ? 'bg-green-500/10 text-green-500 border-green-500/20' : (isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-green-500' : 'bg-white text-gray-400 border-gray-100 hover:text-green-600')}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 10h4.708c.944 0 1.708.764 1.708 1.708 0 .178-.027.354-.08.524l-2.09 6.556A1.708 1.708 0 0116.635 20H7V10l3.745-7.489c.355-.71 1.258-.87 1.826-.32l2.429 2.429V10zM7 10H3v10h4V10z" />
                                                    </svg>
                                                </button>
                                                <button 
                                                    onClick={() => handleFeedback(idx, 'negative')}
                                                    className={`p-1.5 border rounded-lg shadow-sm transition-colors ${msg.feedback === 'negative' ? 'bg-red-500/10 text-red-500 border-red-500/20' : (isDarkMode ? 'bg-gray-800 text-gray-400 border-gray-700 hover:text-red-500' : 'bg-white text-gray-400 border-gray-100 hover:text-red-600')}`}
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 14H5.292c-.944 0-1.708-.764-1.708-1.708 0-.178.027-.354.08-.524l2.09-6.556A1.708 1.708 0 017.365 4H17v10l-3.745 7.489c-.355.71-1.258.87-1.826.32l-2.429-2.429V14zM17 14h4V4h-4v10z" />
                                                    </svg>
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                        <div className="flex justify-start">
                            <div className={`flex items-center space-x-3 px-5 py-3 rounded-2xl rounded-tl-none border shadow-sm transition-colors ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'}`}>
                                <div className="flex space-x-1">
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                                </div>
                                <span className={`text-xs font-medium italic ${isDarkMode ? 'text-gray-400' : 'text-gray-500'}`}>Analyse en cours...</span>
                            </div>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className={`p-6 border-t transition-colors ${isDarkMode ? 'bg-gray-900 border-gray-800' : 'bg-white border-slate-100'}`}>
                    <div className="max-w-4xl mx-auto mb-4 overflow-x-auto hide-scrollbar flex space-x-2 pb-2">
                        {suggestions.map((suggestion, i) => (
                            <button
                                key={i}
                                onClick={() => handleSend(undefined, suggestion)}
                                className={`whitespace-nowrap px-3 py-1.5 text-[11px] font-bold rounded-full border transition-all uppercase tracking-tight ${
                                    isDarkMode 
                                    ? 'bg-gray-800 text-gray-400 border-gray-700 hover:bg-indigo-900/30 hover:text-indigo-400 hover:border-indigo-500/50' 
                                    : 'bg-slate-50 text-slate-600 border-slate-200 hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-200'
                                }`}
                            >
                                {suggestion}
                            </button>
                        ))}
                    </div>

                    <form onSubmit={handleSend} className="relative max-w-4xl mx-auto">
                        <input
                            type="text"
                            placeholder="Interrogez l'IA sur vos dossiers ou clients..."
                            className={`w-full p-4 pr-16 border rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all text-sm ${
                                isDarkMode 
                                ? 'bg-gray-800 border-gray-700 text-gray-100 placeholder-gray-500 hover:bg-gray-700/50' 
                                : 'bg-slate-50 border-slate-200 text-gray-900 placeholder-slate-400 hover:bg-white'
                            }`}
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={isLoading}
                        />
                        <button 
                            type="submit" 
                            disabled={isLoading || !input.trim()}
                            className="absolute right-2 top-2 bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 disabled:opacity-50"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                            </svg>
                        </button>
                    </form>
                    <p className={`text-center text-[10px] mt-3 font-medium tracking-wide ${isDarkMode ? 'text-gray-500' : 'text-slate-400'}`}>
                        L'intelligence artificielle peut générer des erreurs. Veuillez vérifier les informations clés.
                    </p>
                </div>
            </div>

            <style>{`
                .hide-scrollbar::-webkit-scrollbar { display: none; }
                .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

                @keyframes fade-in-down {
                    0% { opacity: 0; transform: translate(-50%, -20px); }
                    100% { opacity: 1; transform: translate(-50%, 0); }
                }
                .animate-fade-in-down {
                    animation: fade-in-down 0.3s ease-out;
                }
            `}</style>
        </div>
    );
};

export default AIAssistantPage;

import React, { FC, useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIIcon } from '../components/Icons';
import { Client, Case, Task, Invoice } from '../types';
import { usePersistentState } from '../hooks/usePersistentState';

interface AIAssistantPageProps {
    clients: Client[];
    cases: Case[];
    tasks: Task[];
    invoices: Invoice[];
}

interface Message {
    role: 'user' | 'assistant';
    content: string;
    feedback?: 'positive' | 'negative' | null;
}

interface Conversation {
    id: string;
    title: string;
    messages: Message[];
    timestamp: number;
}

const AIAssistantPage: FC<AIAssistantPageProps> = ({ clients, cases, tasks, invoices }) => {
    const initialAssistantMessage: Message = { 
        role: 'assistant', 
        content: "Bonjour ! Je suis l'assistant IA de KBB App. Je suis maintenant directement connecté à votre base de données. Je peux analyser vos dossiers, calculer vos balances de facturation par client ou identifier vos retards de tâches. Comment puis-je vous aider ?",
        feedback: null
    };

    const [conversations, setConversations] = usePersistentState<Conversation[]>('kbb_ai_history', []);
    const [isDarkMode, setIsDarkMode] = usePersistentState<boolean>('kbb_ai_dark_mode', false);
    const [currentConvId, setCurrentConvId] = useState<string | null>(null);

    const [messages, setMessages] = useState<Message[]>([initialAssistantMessage]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [copyFeedback, setCopyFeedback] = useState<number | null>(null);
    const [errorMessage, setErrorMessage] = useState<string | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Prepare a rich data summary for the AI context
    const dataContextSummary = useMemo(() => {
        return {
            clients: clients.map(c => ({
                id: c.id,
                nom: c.name,
                contact: c.contact,
                dossiersCount: c.cases
            })),
            dossiers: cases.map(c => ({
                ref: c.id,
                nom: c.name,
                client: c.client,
                statut: c.status,
                prochaineAudience: c.nextHearing || "Aucune"
            })),
            taches: tasks.map(t => ({
                nom: t.name,
                dossierRef: t.caseId,
                avocat: t.lawyer,
                echeance: t.dueDate,
                statut: t.status
            })),
            factures: invoices.map(i => ({
                id: i.id,
                dossierRef: i.caseId,
                echeance: i.dueDate,
                total: i.totalAmount,
                paye: i.paidAmount,
                du: i.totalAmount - i.paidAmount,
                statut: i.status
            })),
            stats: {
                totalDu: invoices.reduce((acc, inv) => acc + (inv.totalAmount - inv.paidAmount), 0),
                tachesEnRetard: tasks.filter(t => t.status !== 'Effectué' && new Date(t.dueDate) < new Date()).length
            }
        };
    }, [clients, cases, tasks, invoices]);

    const suggestions = [
        "Quels sont les dossiers du client Congo Invest ?",
        "Fais-moi un rapport sur les factures impayées",
        "Liste les tâches urgentes pour Jean-Luc",
        "Analyse la rentabilité par client",
        "Quelles sont les prochaines audiences ?"
    ];

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isLoading]);

    useEffect(() => {
        if (errorMessage) {
            const timer = setTimeout(() => setErrorMessage(null), 6000);
            return () => clearTimeout(timer);
        }
    }, [errorMessage]);

    useEffect(() => {
        if (currentConvId && messages.length > 1) {
            setConversations(prev => prev.map(conv => 
                conv.id === currentConvId ? { ...conv, messages: messages } : conv
            ));
        }
    }, [messages]);

    const handleNewChat = () => {
        setCurrentConvId(null);
        setMessages([initialAssistantMessage]);
        setInput('');
    };

    const handleSelectConversation = (conv: Conversation) => {
        setCurrentConvId(conv.id);
        setMessages(conv.messages);
    };

    const handleDeleteConversation = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (window.confirm("Supprimer cette conversation ?")) {
            setConversations(prev => prev.filter(c => c.id !== id));
            if (currentConvId === id) {
                handleNewChat();
            }
        }
    };

    const handleClearChat = () => {
        if (window.confirm("Voulez-vous vraiment effacer l'historique de cette conversation ?")) {
            setMessages([initialAssistantMessage]);
            if (currentConvId) {
                setConversations(prev => prev.filter(c => c.id !== currentConvId));
                setCurrentConvId(null);
            }
        }
    };

    const handleCopy = (text: string, index: number) => {
        navigator.clipboard.writeText(text);
        setCopyFeedback(index);
        setTimeout(() => setCopyFeedback(null), 2000);
    };

    const handleFeedback = (index: number, type: 'positive' | 'negative') => {
        setMessages(prev => prev.map((msg, i) => 
            i === index ? { ...msg, feedback: msg.feedback === type ? null : type } : msg
        ));
    };

    const handleSend = async (e?: React.FormEvent, overrideInput?: string) => {
        if (e) e.preventDefault();
        const messageToSend = (overrideInput || input).trim();
        if (!messageToSend || isLoading) return;

        let activeId = currentConvId;
        const newMsg: Message = { role: 'user', content: messageToSend };
        const updatedMessages = [...messages, newMsg];

        if (!activeId) {
            const newId = Date.now().toString();
            const newConv: Conversation = {
                id: newId,
                title: messageToSend.length > 30 ? messageToSend.substring(0, 30) + '...' : messageToSend,
                messages: updatedMessages,
                timestamp: Date.now()
            };
            setConversations(prev => [newConv, ...prev]);
            setCurrentConvId(newId);
            activeId = newId;
        }

        setInput('');
        setMessages(updatedMessages);
        setIsLoading(true);
        setErrorMessage(null);

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

            const systemInstruction = `
                Tu es l'assistant expert du cabinet d'avocats KBB. Tu as un accès direct aux données structurées suivantes :
                ${JSON.stringify(dataContextSummary)}

                TES MISSIONS :
                1. Analyse et Croisement : Référence TOUJOURS les identifiants précis. Si on parle d'une facture, mentionne son ID (ex: FACT-...). Si on parle d'un dossier, cite sa Référence (ex: CI-...).
                2. Richesse des réponses : Ne te contente pas de lister. Analyse. Ex: "Le client X a 3 factures impayées pour un total de Z€, dont une est en retard depuis le...".
                3. Proactivité : Si tu vois un problème (ex: dossier clôturé mais facture non réglée), signale-le.
                4. Format : Utilise du Markdown riche (gras pour les noms/IDs, tableaux pour les listes financières, puces pour les tâches).
                5. Ton : Professionnel, juridique, précis et aidant.
                6. Langue : Réponds toujours en Français.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    ...messages.filter(m => m.role !== 'assistant' || m !== initialAssistantMessage).map(m => ({
                        role: m.role === 'user' ? 'user' : 'model',
                        parts: [{ text: m.content }]
                    })),
                    { role: 'user', parts: [{ text: messageToSend }] }
                ],
                config: {
                    systemInstruction: systemInstruction,
                    temperature: 0.3, // Lower temperature for more accurate data reporting
                }
            });

            const assistantResponse = response.text || "Désolé, je n'ai pas pu générer de réponse.";
            setMessages(prev => [...prev, { role: 'assistant', content: assistantResponse, feedback: null }]);
        } catch (error) {
            console.error("AI Error:", error);
            setErrorMessage("Erreur de communication avec l'IA. Vérifiez votre clé API.");
        } finally {
            setIsLoading(false);
        }
    };

    const renderContent = (content: string) => {
        if (content.includes('|') && content.includes('\n|')) {
            const lines = content.split('\n');
            return (
                <div className={`overflow-x-auto my-3 border rounded-xl shadow-inner ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-gray-50/50 border-gray-200'}`}>
                    <table className={`min-w-full divide-y text-xs ${isDarkMode ? 'divide-gray-700 text-gray-200' : 'divide-gray-200 text-gray-800'}`}>
                        <tbody>
                            {lines.map((line, i) => {
                                if (!line.trim().startsWith('|')) return <p key={i} className="px-4 py-2 italic opacity-75">{line}</p>;
                                const cells = line.split('|').filter(c => c.trim() !== '' || line.indexOf('|') !== line.lastIndexOf('|'));
                                if (line.includes('---')) return null;
                                return (
                                    <tr key={i} className={i === 0 ? (isDarkMode ? "bg-gray-700/50 font-bold" : "bg-gray-100/80 font-bold") : "hover:bg-indigo-500/5 transition-colors"}>
                                        {cells.map((cell, j) => (
                                            <td key={j} className="px-4 py-2.5 whitespace-nowrap">{cell.trim()}</td>
                                        ))}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            );
        }

        // Simple regex to bold IDs like FACT-... or CI-... or EVT-...
        const boldedContent = content.replace(/([A-Z]+-[A-Z0-9-]+)/g, '**$1**');

        return <p className="text-sm whitespace-pre-wrap leading-relaxed">{boldedContent}</p>;
    };

    return (
        <div className={`flex h-full max-h-screen -m-8 transition-colors duration-500 ${isDarkMode ? 'bg-gray-950 text-gray-100' : 'bg-white text-gray-900'}`}>
            {/* Sidebar History */}
            <div className={`w-72 border-r flex flex-col h-full overflow-hidden transition-all duration-300 ${isDarkMode ? 'bg-gray-900 border-gray-800 shadow-2xl' : 'bg-slate-100 border-slate-200 shadow-inner'}`}>
