                    background: transparent;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb {
                    background: ${isDarkMode ? '#374151' : '#E2E8F0'};
                    border-radius: 10px;
                }
            `}</style>
        </div>
    );
};

